120	export const getSelectionKeys = (pattern: any): string[] => {
121	  if (isObject(pattern)) {
122	    if (isMatcher(pattern)) {
123	      return pattern[symbols.matcher]().getSelectionKeys?.() ?? [];
124	    }
125	    if (Array.isArray(pattern)) return flatMap(pattern, getSelectionKeys);
