  value: input
): MatchEach<input, output>;
export function matchEach<input, output = symbols.unset>(): MatchEach<
  input,
  output
>;
export function matchEach(...args: any[]): any {
  return new MatchEachExpression(
    args.length > 0 ? args[0] : undefined,
    []
  ) as any;
}

